#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define CACHE_LINE 512

typedef struct {
    float weight;
    long assign;
    float cost;
} Point_Struct;

__kernel void pgain_kernel(
    __global Point_Struct* p,
    __global float* coord,
    __global float* work_mem,
    __global int* center_table,
    __global char* switch_membership,
    __local float* local_coord,
    int num,
    int dim,
    long x,
    int K
    )
{
    int gid = get_global_id(0);
    if (gid >= num) return;

    float x_cost = 0.0f;
    float current_cost = 0.0f;
    // Compute dist(points[gid], points[x]) * weight
    for (int i = 0; i < dim; i++) {
        float diff = coord[gid * dim + i] - coord[x * dim + i];
        x_cost += diff * diff;
    }
    x_cost *= p[gid].weight;

    current_cost = p[gid].cost;

    if (x_cost < current_cost) {
        switch_membership[gid] = 1;
        // atomic add to cost_of_opening_x replaced by local accumulation in host
        // but here we just mark switch_membership
        // cost_of_opening_x is computed on host
    }
    else {
        int assign = p[gid].assign;
        // Accumulate difference in work_mem at center_table[assign]
        // Use atomic add to avoid race conditions
        atomic_add(&work_mem[gid*(K+1) + center_table[assign]], current_cost - x_cost);
        switch_membership[gid] = 0;
    }
}

